code = """import pandas as pd\nimport re\n\nlatest_release_packages = pd.read_json(locals()[\'var_function-call-2139176942415530674\'])\nproject_packageversion = pd.read_json(locals()[\'var_function-call-7421897730721124387\'])\nproject_info = pd.read_json(locals()[\'var_function-call-13735147255475096839\'])\n\n# Merge latest_release_packages with project_packageversion\nmerged_packages = pd.merge(latest_release_packages, project_packageversion, on=[\'Name\', \'Version\'], how=\'inner\')\n\n# Extract ProjectName and Stars from Project_Information\ndef extract_project_info(project_information):\n    project_name_match = re.search(r\'The project (.*?) on GitHub\', project_information)\n    if not project_name_match:\n        project_name_match = re.search(r\'The project named (.*?) on GitHub\', project_information)\n    if not project_name_match:\n        project_name_match = re.search(r\'The GitHub project (.*?) currently has\', project_information)\n    if not project_name_match:\n        project_name_match = re.search(r\'The project (.*?) is hosted on GitHub\', project_information)\n    if not project_name_match:\n        project_name_match = re.search(r\'The project (.*?) is hosted on GITHUB\', project_information)\n    \n    project_name = project_name_match.group(1).strip() if project_name_match else None\n    if project_name and project_name.startswith(\'lberrocal/\'):\n        project_name = project_name.replace(\'lberrocal/\', \'\')\n        \n    stars_match = re.search(r\'(\d{1,3}(?:,\\d{3})*|\d+) stars\', project_information)\n    stars = int(stars_match.group(1).replace(\',\', \'\')) if stars_match else 0\n    return project_name, stars\n\nproject_info_extracted = project_info[\'Project_Information\'].apply(lambda x: pd.Series(extract_project_info(x), index=[\'ProjectName_extracted\', \'Stars\']))\nproject_info_df = pd.concat([project_info, project_info_extracted], axis=1)\n\n# Merge with project_info_df to get star counts. Need to use both extracted project name and ProjectName from packageversion\nfinal_merged_df = pd.merge(merged_packages, project_info_df, left_on=\'ProjectName\', right_on=\'ProjectName_extracted\', how=\'inner\')\n\n# Drop duplicates and sort by stars\nfinal_merged_df = final_merged_df.drop_duplicates(subset=[\'Name\', \'Version\', \'ProjectName\'])\ntop_5_packages = final_merged_df.sort_values(by=\'Stars\', ascending=False).head(5)\n\nresult = top_5_packages[[\'Name\', \'Version\', \'Stars\']].to_json(orient=\'records\')\n\nprint(\'__RESULT__:\')\nprint(result)"""

